/**
 * Order validation — pure validation functions for order operations.
 *
 * These validators contain no side effects and no database calls.
 * They can be reused across any service that needs order-related validation.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed. Throws if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that an order has at least one item. Throws if empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Preferences validation — pure validation functions for notification preferences.
 *
 * These validators contain no side effects and no database calls.
 * They evaluate preference rules against in-memory preference data.
 */

import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';

/**
 * Check whether a notification is allowed by the user's preferences.
 *
 * Rules:
 * 1. If no preferences exist (null), notifications are allowed (opt-out model).
 * 2. If the email channel is disabled, all email notifications are suppressed.
 * 3. If the frequency is 'none', all email notifications are suppressed.
 * 4. If the specific category is disabled, that notification is suppressed.
 * 5. Non-email channels are always allowed (only email preferences are supported).
 */
export function isNotificationAllowed(
  prefs: UserNotificationPreferences | null,
  channel: NotificationChannel,
  type: NotificationType,
): boolean {
  // Only email preferences are supported for now
  if (channel !== 'email') {
    return true;
  }

  // No preferences stored — default is to send everything
  if (!prefs) {
    return true;
  }

  if (!prefs.email.enabled) {
    return false;
  }

  if (prefs.email.frequency === 'none') {
    return false;
  }

  if (prefs.email.categories[type] === false) {
    return false;
  }

  return true;
}

